const allowedDevices = new Set(['m5-01', 'm5-02']);
const topicParts = String(msg.topic || '').split('/');
if (topicParts.length !== 3 || topicParts[0] !== 'devices' || topicParts[2] !== 'telemetry') {
    return null;
}

const deviceId = topicParts[1];
if (!allowedDevices.has(deviceId)) {
    return null;
}

const counters = flow.get('gatewayCounters') || {};
counters.messagesReceived = (counters.messagesReceived || 0) + 1;

let payload = msg.payload;
if (Buffer.isBuffer(payload)) {
    payload = payload.toString('utf8');
}
if (typeof payload === 'string') {
    try {
        payload = JSON.stringify(JSON.parse(payload));
    } catch (err) {
        return null;
    }
} else if (payload && typeof payload === 'object') {
    payload = JSON.stringify(payload);
}

const devices = new Set(flow.get('knownLocalDevices') || []);
devices.add(deviceId);
flow.set('knownLocalDevices', Array.from(devices).sort());
counters.messagesForwarded = (counters.messagesForwarded || 0) + 1;
flow.set('gatewayCounters', counters);

msg.topic = `m5/${deviceId}/telemetry`;
msg.payload = payload;
const handled = (context.get('handled') || 0) + 1;
context.set('handled', handled);
node.status({ fill: 'green', shape: 'dot', text: `${handled} handled` });
return msg;

