}

const counters = flow.get('gatewayCounters') || {};
counters.commandsReceived = (counters.commandsReceived || 0) + 1;
counters.commandsForwarded = (counters.commandsForwarded || 0) + 1;
flow.set('gatewayCounters', counters);

msg.topic = `devices/${deviceId}/cmd/${commandKey}`;
const handled = (context.get('handled') || 0) + 1;
