const allowedDevices = new Set(['m5-01', 'm5-02']);
const topicParts = String(msg.topic || '').split('/');
if (topicParts.length !== 4 || topicParts[0] !== 'devices' || topicParts[2] !== 'rsp' || !topicParts[1] || !topicParts[3]) {
