const counters = flow.get('gatewayCounters') || {};
const startedAt = flow.get('gatewayStartedAt') || Date.now();
flow.set('gatewayStartedAt', startedAt);

const devices = flow.get('knownLocalDevices') || [];
const now = Date.now();
const intervalSeconds = Number(env.get('GATEWAY_METRICS_INTERVAL_SECONDS')) || 60;

msg.payload = {
    time: now * 1000,
    messagesReceived: counters.messagesReceived || 0,
    messagesForwarded: counters.messagesForwarded || 0,
    commandsReceived: counters.commandsReceived || 0,
    commandsForwarded: counters.commandsForwarded || 0,
    responsesForwarded: counters.responsesForwarded || 0,
    localDevices: devices.length,
    uptimeSeconds: Math.floor((now - startedAt) / 1000),
    system: {
        metricsIntervalSeconds: intervalSeconds
    }
};

msg.topic = 'gateway/metrics';
const handled = (context.get('handled') || 0) + 1;
context.set('handled', handled);
node.status({ fill: 'green', shape: 'dot', text: `${handled} handled` });
return msg;

const deviceId = 'm5-01';
const key = `simulator:${deviceId}`;
const defaults = {
    sht_temperature: 22.1,
    qmp_temperature: 22.8,
    humidity: 45,
    pressure: 1013.2,
    count: 0,
    intervalSeconds: 10,
    disabled: false,
    running: false,
    loopToken: null
};
const state = { ...defaults, ...flow.get(key) };
const isLoopMessage = Boolean(msg.loopToken);

function setStoppedStatus() {
    node.status({ fill: 'red', shape: 'ring', text: 'stopped' });
}

if (isLoopMessage && (state.disabled || !state.running)) {
    setStoppedStatus();
    return null;
}
if (isLoopMessage && msg.loopToken !== state.loopToken) {
    return null;
}
if (!isLoopMessage) {
    state.disabled = false;
    state.running = true;
    state.loopToken = `m5-01-${Date.now()}-${Math.random()}`;
}

function vary(value, delta, min, max) {
    const next = Number(value) + ((Math.random() * 2) - 1) * delta;
    return Math.round(Math.min(max, Math.max(min, next)) * 10) / 10;
}

state.intervalSeconds = Math.max(1, Number(state.intervalSeconds) || defaults.intervalSeconds);
state.sht_temperature = vary(state.sht_temperature, 0.3, 18, 30);
state.qmp_temperature = vary(state.qmp_temperature, 0.3, 18, 32);
state.humidity = vary(state.humidity, 1.0, 25, 75);
state.pressure = Math.round(Math.min(1030, Math.max(990, Number(state.pressure) + ((Math.random() * 2) - 1) * 0.8)) * 10) / 10;
state.count = (state.count || 0) + 1;
flow.set(key, state);

const telemetry = {
    topic: `devices/${deviceId}/telemetry`,
    payload: {
        sht_temperature: state.sht_temperature,
        qmp_temperature: state.qmp_temperature,
        humidity: state.humidity,
        pressure: state.pressure,
        count: state.count,
        time: Date.now() * 1000
    }
};

msg.delay = state.intervalSeconds * 1000;
msg.loopToken = state.loopToken;
msg.payload = { deviceId, intervalSeconds: state.intervalSeconds };
const handled = (context.get('handled') || 0) + 1;
context.set('handled', handled);
node.status({ fill: 'green', shape: 'dot', text: `${handled} handled` });
return [telemetry, msg];

const deviceId = 'm5-01';
const topicParts = String(msg.topic || '').split('/');
const commandKey = topicParts[3] || 'command';
const key = `simulator:${deviceId}`;
const defaults = {
    sht_temperature: 22.1,
    qmp_temperature: 22.8,
    humidity: 45,
    pressure: 1013.2,
    count: 0,
    intervalSeconds: 10,
    disabled: false,
    running: false,
    loopToken: null
};
const state = { ...defaults, ...flow.get(key) };

let command = msg.payload;
if (Buffer.isBuffer(command)) {
    command = command.toString('utf8');
}
if (typeof command === 'string') {
    try {
        command = JSON.parse(command);
    } catch (err) {
        command = command.trim();
    }
}
const commandObject = command && typeof command === 'object' && !Array.isArray(command) ? command : {};

const response = {
    deviceId,
    commandKey,
    time: Date.now() * 1000
};

if (commandKey === 'identify' || commandObject.identify === true) {
    response.status = 'identified';
} else if (commandKey === 'setIntervalSeconds' || Object.hasOwn(commandObject, 'setIntervalSeconds')) {
    const intervalValue = Object.hasOwn(commandObject, 'setIntervalSeconds') ? commandObject.setIntervalSeconds : command;
    const intervalSeconds = Math.max(1, Number(intervalValue));
    if (Number.isFinite(intervalSeconds)) {
        state.intervalSeconds = intervalSeconds;
        response.status = 'interval-set';
        response.setIntervalSeconds = state.intervalSeconds;
    } else {
        response.status = 'unsupported';
    }
} else if (commandKey === 'shutdown' || commandObject.shutdown === true) {
    state.disabled = true;
    state.running = false;
    state.loopToken = null;
    response.status = 'shutdown';
} else {
    response.status = 'unsupported';
}

flow.set(key, state);
msg.topic = `devices/m5-01/rsp/${commandKey}`;
msg.payload = JSON.stringify(response);
const handled = (context.get('handled') || 0) + 1;
context.set('handled', handled);
node.status({ fill: 'green', shape: 'dot', text: `${handled} handled` });
return msg;

